"use strict";parserFactory.register("wuxia.city",()=>new WuxiacityParser);class WuxiacityParser extends Parser{constructor(){super()}async getChapterUrls(e){return e.baseURI.endsWith("/table-of-contents")||(e=(await HttpClient.wrapFetch(e.baseURI+"/table-of-contents")).responseXML),[...e.querySelectorAll("ul.chapters a")].reverse().map(WuxiacityParser.linkToChapter)}static linkToChapter(e){return{sourceUrl:e.href,title:e.querySelector(".chapter-name").textContent.replace(/\n/g," ")}}findContent(e){return e.querySelector("#chapter-content")}extractTitleImpl(e){return e.querySelector(".book-name")}findChapterTitle(e){return e.querySelector(".chapter-title p").textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.book-img")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.book-synopsis")]}}